  ('judicial-57112235-moex-00648', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲對A使用之住宅縱火，事後反悔，打匿名電話通知消防隊，但該住宅已燒燬。有關甲之刑責，下列何者 正確？', '["甲成立放火既遂罪", "甲成立放火未遂罪之中止犯", "甲成立自首，得減輕其刑", "甲成立失火罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
