  ('judicial-57112235-moex-00650', 'judicial-57112235', 'judicial-57112235-moex-110-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲是演員，依劇本應持道具槍作出開槍朝丙擊發之動作。乙明知其事，為利用甲殺死丙，暗中將該道具槍 調包為真槍。不知情之甲仍依劇本持槍朝丙射擊，導致丙死亡。下列敘述，何者正確？', '["甲成立故意殺人既遂罪", "乙成立故意殺人既遂罪", "甲成立殺人罪之幫助犯", "乙成立殺人罪之教唆犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
